def test_television_on_off():
    tv = Television(device_id=1)
    assert tv.status == TwoStatus.OFF.value
    assert tv.power_rating == 0
    assert tv.heating_rate == 0


    tv.switch_up()
    assert tv.status == TwoStatus.ON.value
    assert tv.power_rating == config.DEVICE_CONFIG["Television"]["power_rating"]
    assert tv.heating_rate == config.DEVICE_CONFIG["Television"]["heating_rate"]

    tv.switch_down()
    assert tv.status == TwoStatus.OFF.value
    assert tv.power_rating == 0
    assert tv.heating_rate == 0

