def test_air_conditioner_initial_state():
    ac = AirConditioner(device_id=101)
    assert ac.status == 0
    assert ac.power_rating == config.AIR_CONDITIONER_CONFIG[ACStatus.OFF]["power"]
    assert ac.heating_rate == config.AIR_CONDITIONER_CONFIG[ACStatus.OFF]["heating_rate"]

def test_air_conditioner_switch_up_levels():
    ac = AirConditioner(device_id=102)

    start_level = ac.status
    ac.switch_up()  # From 0 to 1 
    assert ac.status == 1
    assert ac.power_rating == config.AIR_CONDITIONER_CONFIG[ACStatus.HEATING_LEVEL_1]["power"]
    assert ac.heating_rate == config.AIR_CONDITIONER_CONFIG[ACStatus.HEATING_LEVEL_1]["heating_rate"]

    ac.switch_up()  # From 1 to 2 
    assert ac.status == 2
    assert ac.power_rating == config.AIR_CONDITIONER_CONFIG[ACStatus.HEATING_LEVEL_2]["power"]
    assert ac.heating_rate == config.AIR_CONDITIONER_CONFIG[ACStatus.HEATING_LEVEL_2]["heating_rate"]

def test_air_conditioner_switch_down_levels():
    ac = AirConditioner(device_id=103)
    
    ac.switch_up()  # From 0 to 1
    ac.switch_up()  # From 1 to 2
    
    ac.switch_down()  # From 2 to 1
    assert ac.status == 1
    assert ac.power_rating == config.AIR_CONDITIONER_CONFIG[ACStatus.HEATING_LEVEL_1]["power"]
    assert ac.heating_rate == config.AIR_CONDITIONER_CONFIG[ACStatus.HEATING_LEVEL_1]["heating_rate"]
